use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Compares two real numbers with six significant digits of precision.
/// Returns "LT" if a < b, "EQ" if a == b, "GT" if a > b.
fn realcompare(a: f64, b: f64) -> &'static str {
    // Compare with respect to six most significant digits
    // We use relative comparison for non-zero values
    if a == b {
        return "EQ";
    }

    let max_abs = a.abs().max(b.abs());
    if max_abs == 0.0 {
        return "EQ";
    }

    // Six significant digits means relative tolerance of 1e-6
    let tolerance = max_abs * 1e-6;

    if (a - b).abs() <= tolerance {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

/// Calculate distance between two points
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

/// Calculate area of triangle given three vertices using the shoelace formula
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

/// Determine which quadrant a point lies in (1, 2, 3, or 4)
/// Priority: I, II, III, IV for ambiguous cases
fn quadrant(x: f64, y: f64) -> u8 {
    // Quadrant I: x >= 0 and y >= 0 (includes positive x-axis, positive y-axis, and origin)
    // Quadrant II: x < 0 and y >= 0 (includes negative x-axis)
    // Quadrant III: x < 0 and y < 0
    // Quadrant IV: x >= 0 and y < 0 (includes negative y-axis when x >= 0)

    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x < 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

/// Calculate the angle at vertex (x2, y2) formed by points (x1, y1) -> (x2, y2) -> (x3, y3)
/// Returns None if vertex coincides with either endpoint
fn angle_at_vertex(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    // Check if first or last point coincides with vertex
    let d1 = distance(x1, y1, x2, y2);
    let d2 = distance(x3, y3, x2, y2);

    if realcompare(d1, 0.0) == "EQ" || realcompare(d2, 0.0) == "EQ" {
        return None;
    }

    // Vector from vertex to first point
    let v1x = x1 - x2;
    let v1y = y1 - y2;

    // Vector from vertex to third point
    let v2x = x3 - x2;
    let v2y = y3 - y2;

    // Calculate angle using dot product: cos(angle) = (v1 . v2) / (|v1| * |v2|)
    let dot = v1x * v2x + v1y * v2y;
    let cos_angle = dot / (d1 * d2);

    // Clamp to [-1, 1] to handle floating point errors
    let cos_angle = cos_angle.clamp(-1.0, 1.0);

    Some(cos_angle.acos())
}

/// Check if three points can be contained within or on a circle of given radius
fn can_contain_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // If all three points are the same, they can be contained in any circle with radius >= 0
    let d12 = distance(x1, y1, x2, y2);
    let d23 = distance(x2, y2, x3, y3);
    let d13 = distance(x1, y1, x3, y3);

    // Find the maximum distance between any two points
    let max_dist = d12.max(d23).max(d13);

    // If max distance > 2*radius, points cannot fit in the circle
    if realcompare(max_dist, 2.0 * radius) == "GT" {
        return false;
    }

    // Check if points are collinear (area is zero)
    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if realcompare(area, 0.0) == "EQ" {
        // Collinear points: they fit in circle if max distance <= 2*radius
        return realcompare(max_dist, 2.0 * radius) != "GT";
    }

    // For non-collinear points, calculate circumradius
    // Circumradius R = (a * b * c) / (4 * area)
    let circumradius = (d12 * d23 * d13) / (4.0 * area);

    // Points can be contained if circumradius <= radius
    realcompare(circumradius, radius) != "GT"
}

/// Calculate perpendicular distance from point (px, py) to line defined by (x1, y1) and (x2, y2)
fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let line_len = distance(x1, y1, x2, y2);

    if realcompare(line_len, 0.0) == "EQ" {
        // Line endpoints coincide, return distance from point to that coincident point
        return distance(px, py, x1, y1);
    }

    // Use the formula: |cross product| / |line length|
    // Cross product of (p - p1) and (p2 - p1)
    let cross = ((x2 - x1) * (y1 - py) - (x1 - px) * (y2 - y1)).abs();
    cross / line_len
}

/// LIC 1: Two consecutive points with distance > LENGTH1
fn lic1(input: &DecideInput) -> bool {
    let length1 = input.parameters.length1;
    for i in 0..input.numpoints - 1 {
        let d = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 2: Three consecutive points that cannot be contained in circle of radius RADIUS1
fn lic2(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let radius1 = input.parameters.radius1;
    for i in 0..input.numpoints - 2 {
        if !can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
            radius1,
        ) {
            return true;
        }
    }
    false
}

/// LIC 3: Three consecutive points forming angle < (PI - EPSILON) or > (PI + EPSILON)
fn lic3(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let epsilon = input.parameters.epsilon;
    for i in 0..input.numpoints - 2 {
        if let Some(angle) = angle_at_vertex(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
        ) {
            if realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

/// LIC 4: Three consecutive points forming triangle with area > AREA1
fn lic4(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let area1 = input.parameters.area1;
    for i in 0..input.numpoints - 2 {
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
        );
        if realcompare(area, area1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 5: Q_PTS consecutive points in more than QUADS quadrants
fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;

    if input.numpoints < q_pts {
        return false;
    }

    for i in 0..=input.numpoints - q_pts {
        let mut quadrant_flags = [false; 4];
        for j in 0..q_pts {
            let q = quadrant(input.x[i + j], input.y[i + j]);
            quadrant_flags[(q - 1) as usize] = true;
        }
        let num_quadrants: usize = quadrant_flags.iter().filter(|&&x| x).count();
        if num_quadrants > quads {
            return true;
        }
    }
    false
}

/// LIC 6: Two consecutive points where X[j] - X[i] < 0 (j = i + 1)
fn lic6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints - 1 {
        let diff = input.x[i + 1] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// LIC 7: N_PTS consecutive points where at least one is > DIST from line joining first and last
fn lic7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let n_pts = input.parameters.n_pts;
    let dist = input.parameters.dist;

    if input.numpoints < n_pts {
        return false;
    }

    for i in 0..=input.numpoints - n_pts {
        let first_idx = i;
        let last_idx = i + n_pts - 1;

        let x1 = input.x[first_idx];
        let y1 = input.y[first_idx];
        let x2 = input.x[last_idx];
        let y2 = input.y[last_idx];

        let endpoints_coincide = realcompare(distance(x1, y1, x2, y2), 0.0) == "EQ";

        for j in first_idx + 1..last_idx {
            let d = if endpoints_coincide {
                distance(input.x[j], input.y[j], x1, y1)
            } else {
                point_to_line_distance(input.x[j], input.y[j], x1, y1, x2, y2)
            };

            if realcompare(d, dist) == "GT" {
                return true;
            }
        }
    }
    false
}

/// LIC 8: Two points separated by exactly K_PTS intervening points with distance > LENGTH1
fn lic8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;

    // Points at indices i and i + k_pts + 1 are separated by exactly k_pts intervening points
    for i in 0..input.numpoints {
        let j = i + k_pts + 1;
        if j >= input.numpoints {
            break;
        }
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 9: Three points separated by A_PTS and B_PTS that cannot be contained in circle of RADIUS1
fn lic9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;

    // Points at i, i + a_pts + 1, i + a_pts + 1 + b_pts + 1
    for i in 0..input.numpoints {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if k >= input.numpoints {
            break;
        }
        if !can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            radius1,
        ) {
            return true;
        }
    }
    false
}

/// LIC 10: Three points separated by C_PTS and D_PTS forming angle < (PI - EPSILON) or > (PI + EPSILON)
fn lic10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    let epsilon = input.parameters.epsilon;

    for i in 0..input.numpoints {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;
        if k >= input.numpoints {
            break;
        }
        if let Some(angle) = angle_at_vertex(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        ) {
            if realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

/// LIC 11: Three points separated by E_PTS and F_PTS forming triangle with area > AREA1
fn lic11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;

    for i in 0..input.numpoints {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        if k >= input.numpoints {
            break;
        }
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(area, area1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 12: Two points separated by G_PTS where X[j] - X[i] < 0 (i < j)
fn lic12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let g_pts = input.parameters.g_pts;

    for i in 0..input.numpoints {
        let j = i + g_pts + 1;
        if j >= input.numpoints {
            break;
        }
        let diff = input.x[j] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// LIC 13: Two points separated by K_PTS with distance > LENGTH1 AND
///         Two points separated by K_PTS with distance < LENGTH2
fn lic13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;
    let length2 = input.parameters.length2;

    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..input.numpoints {
        let j = i + k_pts + 1;
        if j >= input.numpoints {
            break;
        }
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, length1) == "GT" {
            found_gt = true;
        }
        if realcompare(d, length2) == "LT" {
            found_lt = true;
        }
        if found_gt && found_lt {
            return true;
        }
    }
    found_gt && found_lt
}

/// LIC 14: Three points separated by A_PTS and B_PTS that cannot be in circle of RADIUS1 AND
///         Three points separated by A_PTS and B_PTS that can be in circle of RADIUS2
fn lic14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;
    let radius2 = input.parameters.radius2;

    let mut found_cannot = false;
    let mut found_can = false;

    for i in 0..input.numpoints {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if k >= input.numpoints {
            break;
        }

        let can_r1 = can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            radius1,
        );
        let can_r2 = can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            radius2,
        );

        if !can_r1 {
            found_cannot = true;
        }
        if can_r2 {
            found_can = true;
        }
        if found_cannot && found_can {
            return true;
        }
    }
    found_cannot && found_can
}

/// LIC 15: Three points separated by E_PTS and F_PTS with area > AREA1 AND
///         Three points separated by E_PTS and F_PTS with area < AREA2
fn lic15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;
    let area2 = input.parameters.area2;

    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..input.numpoints {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        if k >= input.numpoints {
            break;
        }
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(area, area1) == "GT" {
            found_gt = true;
        }
        if realcompare(area, area2) == "LT" {
            found_lt = true;
        }
        if found_gt && found_lt {
            return true;
        }
    }
    found_gt && found_lt
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    // Calculate CMV (Conditions Met Vector)
    let cmv = vec![
        lic1(input),   // CMV[0] = LIC 1
        lic2(input),   // CMV[1] = LIC 2
        lic3(input),   // CMV[2] = LIC 3
        lic4(input),   // CMV[3] = LIC 4
        lic5(input),   // CMV[4] = LIC 5
        lic6(input),   // CMV[5] = LIC 6
        lic7(input),   // CMV[6] = LIC 7
        lic8(input),   // CMV[7] = LIC 8
        lic9(input),   // CMV[8] = LIC 9
        lic10(input),  // CMV[9] = LIC 10
        lic11(input),  // CMV[10] = LIC 11
        lic12(input),  // CMV[11] = LIC 12
        lic13(input),  // CMV[12] = LIC 13
        lic14(input),  // CMV[13] = LIC 14
        lic15(input),  // CMV[14] = LIC 15
    ];

    // Calculate PUM (Preliminary Unlocking Matrix)
    let mut pum = vec![vec![false; 15]; 15];

    // Set diagonal from input
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }

    // Set off-diagonal elements based on LCM and CMV
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            let connector = &input.lcm[i][j];
            pum[i][j] = match connector.as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
        }
    }

    // Calculate FUV (Final Unlocking Vector)
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            // Diagonal is false, so this LIC should not hold back launch
            fuv[i] = true;
        } else {
            // Check if all elements in row i are true
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    // Calculate LAUNCH decision
    let launch = fuv.iter().all(|&x| x);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
